const body = $input.item.json.body;
const message = body.message || '';
const userId = body.userId || '';
const organizationId = body.organizationId || null;
const departmentId = body.departmentId || null;
const sessionId = body.sessionId || userId;
const fileId = body.fileId || null;

if (!message || !userId) {
  throw new Error('message and userId are required');
}

return {
  message: message,
  userId: userId,
  organizationId: organizationId,
  departmentId: departmentId,
  sessionId: sessionId,
  fileId: fileId
};

const parseData = $input.item.json;

// Build vector search filter - ONLY organization level
let vectorFilter = {};

if (parseData.organizationId !== null) {
  vectorFilter['organizationId'] = parseData.organizationId;
}

if (parseData.fileId) {
  vectorFilter['fileId'] = parseData.fileId;
}

return {
  chatInput: parseData.message,
  userId: parseData.userId,
  organizationId: parseData.organizationId,
  departmentId: parseData.departmentId,
  sessionId: parseData.sessionId,
  fileId: parseData.fileId,
  vectorFilter: JSON.stringify(vectorFilter)
};

const { MongoClient } = require('mongodb');
const { GoogleGenerativeAI } = require('@google/generative-ai');

// Get input
const query = $input.item.json.chatInput;
const organizationId = $input.item.json.organizationId;
const departmentId = $input.item.json.departmentId;
const fileId = $input.item.json.fileId;

// Generate embedding
const genAI = new GoogleGenerativeAI(process.env.GEMINI_API_KEY);
const embedModel = genAI.getGenerativeModel({ model: 'text-embedding-004' });
const embedResult = await embedModel.embedContent(query);
const queryVector = embedResult.embedding.values;

// Connect to MongoDB
const client = new MongoClient(process.env.MONGODB_URI);
await client.connect();
const db = client.db('ragchatbot');

// STEP 1: Try dept-specific search first (if user has dept)
let results = [];

if (departmentId) {
  const deptFilter = {
    organizationId: organizationId,
    $or: [
      { departmentId: departmentId },
      { departmentId: null }
    ]
  };

  if (fileId) {
    deptFilter.fileId = fileId;
  }

  const deptPipeline = [
    {
      $vectorSearch: {
        index: 'rag_vector_search_1',
        path: 'embedding',
        queryVector: queryVector,
        numCandidates: 50,
        limit: 5
      }
    },
    { $match: deptFilter },
    {
      $project: {
        text: 1,
        fileName: 1,
        departmentId: 1,
        score: { $meta: 'vectorSearchScore' },
        _id: 0
      }
    }
  ];

  results = await db.collection('embedding_files').aggregate(deptPipeline).toArray();

  console.log(`Dept-specific search found ${results.length} results`);
}

// STEP 2: Fallback to org-wide search if no dept results
if (results.length === 0) {
  console.log('Falling back to org-wide search');

  const orgFilter = { organizationId: organizationId };
  if (fileId) {
    orgFilter.fileId = fileId;
  }

  const orgPipeline = [
    {
      $vectorSearch: {
        index: 'rag_vector_search_1',
        path: 'embedding',
        queryVector: queryVector,
        numCandidates: 50,
        limit: 5
      }
    },
    { $match: orgFilter },
    {
      $project: {
        text: 1,
        fileName: 1,
        departmentId: 1,
        score: { $meta: 'vectorSearchScore' },
        _id: 0
      }
    }
  ];

  results = await db.collection('embedding_files').aggregate(orgPipeline).toArray();

  console.log(`Org-wide search found ${results.length} results`);
}

await client.close();

// Format for AI Agent
return results.map(r => ({
  pageContent: r.text,
  metadata: {
    fileName: r.fileName,
    score: r.score,
    departmentId: r.departmentId
  }
}));

const llmOutput = $input.item.json.response || $input.item.json.text || $input.item.json.output || 'No response';

return {
  response: llmOutput
};

